import { describe, expect, it } from "vitest";

import {
  createFogMemory,
  createFloorGeometrySlot,
  createTileGrid,
  updateFogMemory,
  visibleCells
} from "../src/engine/map/index.js";
import {
  createInitialState,
  serialize,
  type EnemyEntityInstance,
  type EntityId,
  type GameState,
  type PlayerItemStack,
  type Position,
  type SerializableRecord
} from "../src/engine/state/index.js";
import { createEmptyBotMemory } from "../src/harness/bots/index.js";
import { balancedPolicy } from "../src/harness/bots/policies/index.js";
import type { ItemDefinition } from "../src/schemas/entities/index.js";
import {
  validDraughtItemFixture,
  validEnemyDefinitionFixture
} from "../src/schemas/fixtures/entities.js";
import {
  makeEffectBundleFixture,
  validHealEffectFixture,
  validQuaffTriggerFixture,
  validSelfTargetingFixture
} from "../src/schemas/fixtures/vocab.js";
import { constructBrowserBotStateView } from "./browser-bot.js";

describe("browser bot policy view bridge", () => {
  it("preserves mid-combat state through serialize/deserialize before policy decide", () => {
    const state = midCombatState();
    const serialized = serialize(state);
    const construction = constructBrowserBotStateView(
      serialized,
      createEmptyBotMemory()
    );
    const decision = balancedPolicy.decide(construction.view);

    expect(construction.state.entities["enemy#1"]?.kind).toBe("enemy");
    expect(construction.state.player.inventory[0]?.itemInstanceId).toBe(
      "item#heal"
    );
    expect(construction.diagnostics.serializedFog.present).toBe(true);
    expect(construction.diagnostics.serializedFog.visible).toBeGreaterThan(0);
    expect(construction.diagnostics.visibleEnemyCount).toBe(1);
    expect(construction.diagnostics.adjacentEnemyCount).toBe(1);
    expect(construction.diagnostics.inventoryCount).toBe(1);
    expect(construction.diagnostics.hp.current).toBe(5);
    expect(construction.view.visible.enemies).toHaveLength(1);
    expect(construction.view.player.inventory).toHaveLength(1);
    expect(construction.view.player.equipment.weapon).toBeNull();
    expect(construction.view.player.level).toBe(3);
    expect(construction.state.player.xp).toBe(42);
    expect(decision.kind).not.toBe("move");
    expect(["attack", "use_item"]).toContain(decision.kind);
  });
});

function midCombatState(): GameState {
  const base = createInitialState("browser-bot-view-mid-combat");
  const playerPosition = { x: 2, y: 2 };
  const grid = createTileGrid({ width: 5, height: 5 });
  const fog = updateFogMemory(
    createFogMemory(grid),
    grid,
    visibleCells(grid, playerPosition, 3)
  );

  return {
    ...base,
    floor: {
      ...base.floor,
      geometry: {
        ...createFloorGeometrySlot(base.floor.geometry.refId, grid),
        opaque: {
          ...grid,
          fog
        } as unknown as SerializableRecord
      }
    },
    player: {
      ...base.player,
      hp: {
        current: 5,
        max: 20
      },
      level: 3,
      xp: 42,
      position: playerPosition,
      inventory: [healingDraught(), ...base.player.inventory.slice(1)]
    },
    entities: {
      "enemy#1": enemy("enemy#1", { x: 3, y: 2 })
    },
    ids: {
      ...base.ids,
      entityCounters: {
        ...base.ids.entityCounters,
        enemy: 1
      }
    }
  };
}

function healingDraught(): PlayerItemStack {
  return {
    itemInstanceId: "item#heal",
    definition: {
      ...validDraughtItemFixture,
      id: "healing-draught",
      name: "Healing Draught",
      draught: {
        effect: makeEffectBundleFixture(
          [validHealEffectFixture],
          validQuaffTriggerFixture,
          validSelfTargetingFixture
        )
      }
    } satisfies ItemDefinition,
    quantity: 1,
    identified: true
  };
}

function enemy(id: EntityId, position: Position): EnemyEntityInstance {
  return {
    id,
    kind: "enemy",
    definition:
      validEnemyDefinitionFixture as unknown as EnemyEntityInstance["definition"],
    position,
    currentHP: validEnemyDefinitionFixture.stats.hp,
    statuses: [],
    behaviorRuntime: {}
  };
}

